const callbackData = String(input.callback_query?.data ?? '').trim();
const callbackId = String(input.callback_query?.id ?? '').trim();
const callbackMessageId = Number(input.callback_query?.message?.message_id ?? 0);
const callbackChatId = String(input.callback_query?.message?.chat?.id ?? '').trim();

if (callbackData) {
  const callbackMatch = callbackData.match(/^brv:(rvw|meta):(c|x|s):([a-z0-9_-]{8,64})$/i);
  if (!callbackMatch) {
    return [];
  }

  const stageCode = String(callbackMatch[1] ?? '').toLowerCase();
  const actionCode = String(callbackMatch[2] ?? '').toLowerCase();
  const token = String(callbackMatch[3] ?? '').trim();
  const mapped = callbackEventType(stageCode, actionCode);

  if (!token || !mapped.event_type) {
    return [];
  }

  return [{
    json: {
      event_type: mapped.event_type,
      session_token: token,
      instruction: '',
      source: 'telegram',
      router_channel: 'callback_query',
      callback_id: callbackId,
      callback_message_id: callbackMessageId,
      callback_chat_id: callbackChatId,
      callback_data: callbackData,
      stage_hint: mapped.stage,
    },
  }];
}

const messageText = String(input.message?.text ?? '').trim();
if (!messageText) {
  return [];
}

// Start command duoc route boi node parser rieng sang luong main.
// Node router reviewer bo qua de tranh xu ly nham thanh doi/tiep/dung.
if (parseStartCommand(messageText) !== null) {
  return [];
}

let command = parseCommand(messageText);

let tableId = '';
try {
  tableId = await ensureDataTable();
} catch (_) {
  return [];
}

let token = parseTokenFromText(messageText);
let sessionRow = null;

if (token) {
  sessionRow = await getSessionByToken(tableId, token);
}

if (!command) {
  if (!sessionRow) {
    sessionRow = await getLatestAwaitingInstructionSession(tableId);
    token = String(sessionRow?.session_token ?? '').trim();
  }

  if (!sessionRow || !token) {
    return [];
  }

  // Khi dang o trang thai cho "doi", cho phep user gui thang noi dung sua
  // (khong bat buoc phai prefix "doi ").
  command = {
    action: 'change',
    instruction: messageText,
  };
}

if (!sessionRow && command.action === 'change' && command.instruction) {
  sessionRow = await getLatestAwaitingInstructionSession(tableId);
  token = String(sessionRow?.session_token ?? '').trim();

  const isAwaitingInstruction = String(sessionRow?.awaiting_instruction ?? '').trim() === '1';
  if (!sessionRow || !token || !isAwaitingInstruction) {
    return [];
  }
}

if (!sessionRow && (command.action === 'continue' || command.action === 'stop')) {
  sessionRow = await getLatestPendingSession(tableId);
  token = String(sessionRow?.session_token ?? '').trim();
}

if (!sessionRow || !token) {
  return [];
}

const stage = String(sessionRow.stage ?? '').trim() || 'review_pending';
const eventType = mapActionToEvent(stage, command.action);

if (!eventType) {
  return [];
}

return [{
  json: {
    event_type: eventType,
    session_token: token,
    instruction: command.action === 'change' ? command.instruction : '',
    source: 'telegram',
    router_channel: 'message',
    message_text: messageText,
    stage_hint: stage,
    chat_id: String(input.message?.chat?.id ?? '').trim(),
    user_id: String(input.message?.from?.id ?? '').trim(),
  },
}];

