    { text: 'Tiep tuc', callback_data: 'brv:rvw:c:' + sessionToken },
    { text: 'Dung', callback_data: 'brv:rvw:s:' + sessionToken },
    { text: 'Doi', callback_data: 'brv:rvw:x:' + sessionToken },
