async function sendFinalMessage(session, headline) {
  const metadata = session.metadata ?? defaultMetadataFallback(null);

  await sendTelegramMessage('[' + headline + '] Session ' + session.session_token + ' da hoan tat.');
  await sendLongReviewPreview('Ban review cuoi:', normalizeReviewForDisplay(session.full_review));

  const metadataLines = [
    'Metadata cuoi:',
    'Title: ' + safeText(metadata.title),
    'Caption: ' + safeText(metadata.caption),
    'Thumbnail: ' + safeText(metadata.thumbnail_text),
    'Hashtags: ' + normalizeHashtags(metadata.hashtags).join(' '),
  ];

  await sendTelegramMessage(metadataLines.join('\n'));
}

if (!eventType) {
  return {
    status: 'skipped',
    stop_reason: 'missing_event_type',
    event_type: '',
    source: sourceInput,
    session_token: sessionTokenInput,
    notify_message: '',
    skip_worker_notify: true,
  };
}

let tableId = '';
let saveError = '';
let workerError = '';
let notifyMessage = '';

try {
  tableId = await ensureDataTable();
} catch (error) {
  workerError = error?.message ? String(error.message) : String(error);
}

const hasTelegramCallback = sourceInput === 'telegram' && safeText(input.callback_id).length > 0;

if (!tableId) {
  if (hasTelegramCallback) {
    const callbackErrorText = 'He thong dang ban. Thu lai sau.';
    await answerCallback(input.callback_id, callbackErrorText);
    await lockCallbackActionMessage(input.callback_chat_id, input.callback_message_id, callbackErrorText);
  }

  return {
    ...input,
    status: 'failed',
    stop_reason: 'datastore_error',
    notify_message: 'Worker cannot access data store: ' + workerError,
    skip_worker_notify: true,
  };
}

const sessionToken = safeText(sessionTokenInput, safeText(input.reviewer_session_token));
let session = null;

if (sessionToken) {
  const row = await getSessionRow(tableId, sessionToken);
  session = deserializeSession(row);
}

if (!session && eventType === 'init_review' && sessionToken) {
  session = bootstrapSessionFromInput(sessionToken);
}

if (!session) {
  if (hasTelegramCallback) {
    const missingSessionText = buildSessionNotFoundActionText();
    await answerCallback(input.callback_id, missingSessionText);
    await lockCallbackActionMessage(input.callback_chat_id, input.callback_message_id, missingSessionText);
  }

  return {
    ...input,
    status: 'failed',
    stop_reason: 'session_not_found',
    session_token: sessionToken,
    notify_message: 'Session not found for event ' + eventType + '. token=' + sessionToken,
    skip_worker_notify: true,
  };
}

const timedOutSession = hasTelegramCallback && isSessionTimedOut(session);

if (hasTelegramCallback) {
  const actionInfoText = timedOutSession
    ? buildTimeoutActionText(session)
    : buildActionInfoText(eventType, instructionInput);
  await answerCallback(input.callback_id, actionInfoText);
  await lockCallbackActionMessage(input.callback_chat_id, input.callback_message_id, actionInfoText);
}

if (timedOutSession) {
  appendCommand(session, {
    stage: safeText(session.stage, 'review_pending'),
    action: 'timeout_override_continue',
    instruction: '',
  });
}

if (!session.review_intro) {
  session.review_intro = extractSectionText(session.full_review, 'intro');
}
if (!session.review_outro) {
  session.review_outro = extractSectionText(session.full_review, 'outro');
}

const instructionText = safeText(instructionInput);

try {
  if (eventType === 'init_review') {
    if (!session.full_review) {
      throw new Error('Session has empty review content.');
    }

    session.stage = 'review_pending';
    session.awaiting_instruction = false;
    session.deadline_at = addSeconds(nowIso(), reviewerTimeoutSeconds);
    session.stop_reason = '';
    session.metadata_error = '';

    appendCommand(session, {
      stage: 'review',
      action: 'init',
      instruction: '',
    });

    await sendReviewPreview(session, 'REVIEW PREVIEW');
    session.qc = await runQc(session);
    await sendReviewQcAndAction(session, 'QC REVIEW');
    notifyMessage = 'Sent review preview first, then QC and action request.';
  } else if (eventType === 'review_change') {
    session.stage = 'review_pending';
    session.deadline_at = addSeconds(nowIso(), reviewerTimeoutSeconds);

    if (!instructionText) {
      session.awaiting_instruction = true;
      appendCommand(session, {
        stage: 'review',
        action: 'change_request_without_instruction',
        instruction: '',
      });
      await sendTelegramMessage('Ban muon doi gi? Hay gui: doi <noi_dung_muon_sua>');
      notifyMessage = 'Review change requested, awaiting instruction.';
    } else {
      session.awaiting_instruction = false;
      session.review_round = asNumber(session.review_round, 0) + 1;
      await sendTelegramMessage(buildChangeAckMessage('review', instructionText));

      try {
        const revised = await reviseReview(session.full_review, instructionText, session.user_input);
        session.full_review = revised;
        session.review_intro = extractSectionText(session.full_review, 'intro');
        session.review_outro = extractSectionText(session.full_review, 'outro');
        session.metadata_error = '';

        appendCommand(session, {
          stage: 'review',
          action: 'change',
          instruction: instructionText,
        });

        await sendReviewPreview(session, 'REVIEW PREVIEW (UPDATED)');
        session.qc = await runQc(session);
        await sendReviewQcAndAction(session, 'QC REVIEW (UPDATED)');
        notifyMessage = 'Review revised; preview sent first, then QC + action.';
      } catch (error) {
        const errorText = error?.message ? String(error.message) : String(error);
        session.metadata_error = errorText;

        appendCommand(session, {
          stage: 'review',
          action: 'change_failed',
          instruction: instructionText,
          error: errorText,
        });

        await sendTelegramMessage('Khong the sua review bang AI: ' + errorText.slice(0, 700));
        notifyMessage = 'Review revise failed: ' + errorText;
      }
    }
  } else if (eventType === 'review_continue' || eventType === 'auto_continue_review') {
    session.awaiting_instruction = false;
    session.stage = 'metadata_pending';
    session.deadline_at = addSeconds(nowIso(), reviewerTimeoutSeconds);

    try {
      session.metadata = await generateMetadataBundle(session, '', session.metadata ?? null);
      session.metadata_error = '';
    } catch (error) {
      const errorText = error?.message ? String(error.message) : String(error);
      session.metadata_error = errorText;
      session.metadata = defaultMetadataFallback(session.metadata);
    }

    appendCommand(session, {
      stage: 'review',
      action: eventType === 'auto_continue_review' ? 'auto_continue' : 'continue',
      instruction: '',
    });

    await sendMetadataPreview(session, 'METADATA PREVIEW');
    notifyMessage = eventType === 'auto_continue_review'
      ? 'Auto-continued from review stage to metadata stage.'
      : 'Continued from review stage to metadata stage.';
  } else if (eventType === 'review_stop') {
    session.awaiting_instruction = false;
    session.stage = 'completed';
    session.deadline_at = '';
    session.stop_reason = 'reviewer_stopped';

    appendCommand(session, {
      stage: 'review',
      action: 'stop',
      instruction: '',
    });

    await sendTelegramMessage('Da dung luong review theo yeu cau reviewer. Session: ' + session.session_token);
    notifyMessage = 'Reviewer stopped at review stage.';
  } else if (eventType === 'metadata_change') {
    session.stage = 'metadata_pending';
    session.deadline_at = addSeconds(nowIso(), reviewerTimeoutSeconds);

    if (!instructionText) {
      session.awaiting_instruction = true;
      appendCommand(session, {
        stage: 'metadata',
        action: 'change_request_without_instruction',
        instruction: '',
      });
      await sendTelegramMessage('Ban muon doi metadata gi? Hay gui: doi <field + noi_dung_muon_sua>');
      notifyMessage = 'Metadata change requested, awaiting instruction.';
    } else {
      session.awaiting_instruction = false;
      session.metadata_round = asNumber(session.metadata_round, 0) + 1;
      await sendTelegramMessage(buildChangeAckMessage('metadata', instructionText));

      try {
        session.metadata = await generateMetadataBundle(session, instructionText, session.metadata ?? null);
        session.metadata_error = '';

        appendCommand(session, {
          stage: 'metadata',
          action: 'change',
          instruction: instructionText,
        });

        await sendMetadataPreview(session, 'METADATA PREVIEW (UPDATED)');
        notifyMessage = 'Metadata updated and preview re-sent.';
      } catch (error) {
        const errorText = error?.message ? String(error.message) : String(error);
        session.metadata_error = errorText;

        appendCommand(session, {
          stage: 'metadata',
          action: 'change_failed',
          instruction: instructionText,
          error: errorText,
        });

        await sendTelegramMessage('Khong the cap nhat metadata: ' + errorText.slice(0, 700));
        notifyMessage = 'Metadata update failed: ' + errorText;
      }
    }
  } else if (eventType === 'metadata_continue' || eventType === 'auto_continue_metadata') {
    session.awaiting_instruction = false;
    session.stage = 'completed';
    session.deadline_at = '';
    session.stop_reason = 'completed';

    appendCommand(session, {
      stage: 'metadata',
      action: eventType === 'auto_continue_metadata' ? 'auto_continue' : 'continue',
      instruction: '',
    });

    await sendFinalMessage(session, 'FINAL OUTPUT');
    notifyMessage = eventType === 'auto_continue_metadata'
      ? 'Auto-continued metadata stage and finalized output.'
      : 'Metadata approved and output finalized.';
  } else if (eventType === 'metadata_stop') {
    session.awaiting_instruction = false;
    session.stage = 'completed';
    session.deadline_at = '';
    session.stop_reason = 'reviewer_stopped';

    appendCommand(session, {
      stage: 'metadata',
      action: 'stop',
      instruction: '',
    });

    await sendTelegramMessage('Da dung luong metadata theo yeu cau reviewer. Session: ' + session.session_token);
    notifyMessage = 'Reviewer stopped at metadata stage.';
  } else {
    throw new Error('Unsupported event_type: ' + eventType);
  }
} catch (error) {
  workerError = error?.message ? String(error.message) : String(error);
  appendCommand(session, {
    stage: String(session.stage ?? 'unknown'),
    action: 'worker_error',
    instruction: instructionText,
    error: workerError,
  });
  notifyMessage = 'Worker error: ' + workerError;
  session.stop_reason = session.stop_reason || 'worker_error';
}

session.updated_at = nowIso();

if (session.stage === 'completed' && !session.stop_reason) {
  session.stop_reason = 'completed';
}

const qc = session.qc ?? null;
const metadata = session.metadata ?? null;

try {
  await saveSession(tableId, session);
} catch (error) {
  saveError = error?.message ? String(error.message) : String(error);
}

const status = workerError || saveError ? 'failed' : 'success';
const finalNotifyMessage = [notifyMessage, workerError ? 'worker_error=' + workerError : '', saveError ? 'save_error=' + saveError : '']
  .filter(Boolean)
  .join(' | ')
  .slice(0, 1200);

return {
  ...input,
  status,
  event_type: eventType,
  source: sourceInput,
  session_token: session.session_token,
  reviewer_stage: session.stage,
  stop_reason: session.stop_reason || '',
  notify_message: finalNotifyMessage || 'Worker processed event.',
  worker_error: workerError || null,
  save_error: saveError || null,
  full_review: session.full_review,
  review_intro: session.review_intro,
  review_outro: session.review_outro,
  metadata: metadata,
  metadata_status: metadata ? 'generated' : session.stage === 'metadata_pending' ? 'pending' : 'skip',
  metadata_error: session.metadata_error || null,
  video_title: safeText(metadata?.title),
  video_caption: safeText(metadata?.caption),
  video_thumbnail_text: safeText(metadata?.thumbnail_text),
  video_hashtags: Array.isArray(metadata?.hashtags) ? metadata.hashtags : [],
  qc_status: qc?.qc_status ?? 'missing',
  hook_score: qc?.hook_score ?? null,
  clarity_score: qc?.clarity_score ?? null,
  originality_score: qc?.originality_score ?? null,
  practical_value_score: qc?.practical_value_score ?? null,
  risk_level: qc?.risk_level ?? 'med',
  feedback: safeText(qc?.feedback),
  score_warnings: Array.isArray(qc?.score_warnings) ? qc.score_warnings : [],
  reviewer_commands: Array.isArray(session.commands) ? session.commands : [],
  skip_worker_notify: false,
};

const input = $json ?? {};

const hasEventType = String(input.event_type ?? '').trim().length > 0;

if (input.skip_worker_notify === true || !hasEventType) {
  const skippedPayload = {
    status: 'info',
    source_workflow: 'Book Review Gemini via CLIProxyAPI',
    summary: 'Worker skipped notify payload (no event_type or skip_worker_notify=true)',
    details: [
      'skip_worker_notify=' + String(input.skip_worker_notify === true),
      'event_type=' + String(input.event_type ?? ''),
    ].join(' | '),
    message: '',
    message_ack: '',
    session_token: String(input.session_token ?? '').trim(),
    reviewer_stage: String(input.reviewer_stage ?? '').trim(),
    stop_reason: String(input.stop_reason ?? '').trim(),
    notify_targets: 'none',
    telegram_bot_token: String(input.telegram_bot_token ?? '').trim(),
    telegram_chat_id: String(input.telegram_chat_id ?? '').trim(),
    ggchat_webhook_url: String(input.ggchat_webhook_url ?? '').trim(),
    shared_notification_workflow_path: String(input.shared_notification_workflow_path ?? '').trim(),
    chat_priority: 5,
    skip_chat_response: true,
    timestamp: new Date().toISOString(),
  };

  return {
    ...input,
    ...skippedPayload,
    send_informations: [skippedPayload],
  };
}

const rawStatus = String(input.status ?? 'failed').trim() === 'success' ? 'success' : 'failed';
const eventType = String(input.event_type ?? '').trim();
const token = String(input.session_token ?? '').trim();
const stage = String(input.reviewer_stage ?? '').trim();
const stopReason = String(input.stop_reason ?? '').trim();

const isFailure = rawStatus === 'failed';
const isFinalSuccess = eventType === 'metadata_continue' || eventType === 'auto_continue_metadata';

const status = isFailure ? 'failed' : (isFinalSuccess ? 'success' : 'info');

const summary = eventType === 'init_review'
  ? 'Review preview đã gửi, đang chờ reviewer action.'
  : [
      'Worker processed',
      eventType ? 'event=' + eventType : 'event=unknown',
      token ? 'session=' + token : '',
      stage ? 'stage=' + stage : '',
    ].filter(Boolean).join(' ');

const details = [
  stopReason ? 'stop_reason=' + stopReason : null,
  input.worker_error ? 'worker_error=' + String(input.worker_error).slice(0, 220) : null,
  input.save_error ? 'save_error=' + String(input.save_error).slice(0, 220) : null,
  input.notify_message ? 'notify=' + String(input.notify_message).slice(0, 400) : null,
].filter(Boolean).join(' | ') || 'worker-event-processed';

// Chi notify khi fail hoac da hoan tat (success cuoi), tranh spam INFO giua luong.
const shouldNotifyExternally = status === 'failed' || status === 'success';
const notifyTargets = eventType === 'init_review' || !shouldNotifyExternally
  ? 'none'
  : String(input.notify_targets ?? 'telegram');

const payload = {
  status,
  source_workflow: 'Book Review Gemini via CLIProxyAPI',
  summary,
  details,
  message: '',
  message_ack: '',
  session_token: token,
  reviewer_stage: stage,
  stop_reason: stopReason,
  notify_targets: notifyTargets,
  telegram_bot_token: String(input.telegram_bot_token ?? '').trim(),
  telegram_chat_id: String(input.telegram_chat_id ?? '').trim(),
  ggchat_webhook_url: String(input.ggchat_webhook_url ?? '').trim(),
  shared_notification_workflow_path: String(input.shared_notification_workflow_path ?? '').trim(),
  chat_priority: 20,
  skip_chat_response: true,
  timestamp: new Date().toISOString(),
};

return {
  ...input,
  ...payload,
  send_informations: [payload],
};

const input = $json ?? {};

const userInput = String(input.user_input ?? input.chatInput ?? '').trim();
const message = userInput
  ? 'Bắt đầu review: ' + userInput
  : 'Bắt đầu review.';

const payload = {
  status: 'info',
  source_workflow: 'Book Review Gemini via CLIProxyAPI',
  summary: message,
  details: '',
  message,
  message_ack: message,
  session_token: '',
  reviewer_stage: 'starting',
  stop_reason: '',
  notify_targets: String(input.notify_targets ?? 'telegram'),
  telegram_bot_token: String(input.telegram_bot_token ?? '').trim(),
  telegram_chat_id: String(input.telegram_chat_id ?? '').trim(),
  ggchat_webhook_url: String(input.ggchat_webhook_url ?? '').trim(),
  shared_notification_workflow_path: String(input.shared_notification_workflow_path ?? '').trim(),
  chat_priority: 100,
  skip_chat_response: false,
  timestamp: new Date().toISOString(),
};

return {
  ...input,
  ...payload,
  send_informations: [payload],
};

const input = $input.first()?.json ?? {};

const text = String(input.message?.text ?? '').trim();
if (!text) {
  return [];
}

const match = text.match(/^(?:\/)?book(?:[\s_-]?review)\s*[:\-]?\s*([\s\S]*)$/i);
if (!match) {
  return [];
}

const userInput = String(match[1] ?? '').trim();

return [{
  json: {
    ...input,
    chatInput: userInput,
    user_input: userInput,
    start_source: 'telegram_command',
    start_command: 'book-review',
    start_message_text: text,
    chat_id: String(input.message?.chat?.id ?? '').trim(),
    user_id: String(input.message?.from?.id ?? '').trim(),
  },
}];
